#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#define MOD 330301441
#define MAXN 100005
#define MAXK 11
#define MAXX 1018

int mex(int* arr, int n) {
    int* count = (int*)calloc(MAXN, sizeof(int));
    for (int i = 0; i < n; i++) {
        count[arr[i]]++;
    }
    int mex = 0;
    while (count[mex] > 0) {
        mex++;
    }
    free(count);
    return mex;
}

int powmod(int a, int b, int mod) {
    int res = 1;
    while (b > 0) {
        if (b & 1) {
            res = (res * a) % mod;
        }
        a = (a * a) % mod;
        b >>= 1;
    }
    return res;
}

int inv(int a, int mod) {
    return powmod(a, mod - 2, mod);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K, X;
        scanf("%d %d %d", &N, &K, &X);
        int* arr = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
        }
        int* mex_values = (int*)malloc((1 << N) * sizeof(int));
        for (int i = 0; i < (1 << N); i++) {
            int* subseq = (int*)malloc(N * sizeof(int));
            int subseq_len = 0;
            for (int j = 0; j < N; j++) {
                if (i & (1 << j)) {
                    subseq[subseq_len++] = arr[j];
                }
            }
            mex_values[i] = mex(subseq, subseq_len);
            free(subseq);
        }
        int* xor_sum = (int*)malloc((1 << N) * sizeof(int));
        for (int i = 0; i < (1 << N); i++) {
            int sum = 0;
            for (int j = 0; j < N; j++) {
                if (i & (1 << j)) {
                    sum ^= mex_values[j];
                }
            }
            xor_sum[i] = sum;
        }
        int cheftated_value = 0;
        for (int i = 0; i < (1 << N); i++) {
            cheftated_value = (cheftated_value + (xor_sum[i] * inv(powmod(2, X, MOD), MOD))) % MOD;
        }
        printf("%d\n", cheftated_value);
        free(arr);
        free(mex_values);
        free(xor_sum);
    }
    return 0;
}

